mapper.select:
SELECT m.*, c.category_name AS category_name
FROM sys_flow_model m
LEFT JOIN sys_flow_category c ON c.id = m.category OR c.category_code = m.category

    m.del_flag = '0'

        AND m.model_name LIKE CONCAT('%', #{modelName}, '%')


        AND (
            m.category = #{category}
            OR EXISTS (
                SELECT 1
                FROM sys_flow_category fc
                JOIN sys_flow_category selected ON selected.id = #{category} OR selected.category_code = #{category}
                WHERE (fc.id = m.category OR fc.category_code = m.category)
                  AND (fc.id = selected.id OR fc.ancestors LIKE CONCAT('%', selected.id, '/%'))
            )
        )


        AND m.status = #{status}


        AND m.create_by = #{createBy}


ORDER BY m.create_time DESC
